import { __decorate } from "tslib";
import { ChangeDetectionStrategy, Component, Input, ViewEncapsulation, inject, } from '@angular/core';
import { LucideAngularModule, Info, CircleCheck, TriangleAlert, CircleX, X } from 'lucide-angular';
import { PfToastService } from './toast.service';
const VARIANT_ICON = {
    info: Info,
    success: CircleCheck,
    warning: TriangleAlert,
    danger: CircleX,
};
/**
 * Région d'affichage des toasts émis par `PfToastService`.
 * À monter une fois dans le AppComponent.
 */
let PfToastViewportComponent = class PfToastViewportComponent {
    constructor() {
        this.position = 'top-right';
        this.ariaLabel = 'Notifications';
        this.toastService = inject(PfToastService);
        this.XIcon = X;
    }
    iconFor(variant) {
        return VARIANT_ICON[variant];
    }
    static { this.propDecorators = {
        position: [{ type: Input }],
        ariaLabel: [{ type: Input }]
    }; }
};
