        changeDetection: ChangeDetectionStrategy.OnPush,
        encapsulation: ViewEncapsulation.None,
        template: `
    <ol
      role="region"
      [attr.aria-label]="ariaLabel"
      aria-live="polite"
      [class]="'ds-toast-viewport ds-toast-viewport--' + position"
    >
      @for (t of toastService.toasts(); track t.id) {
        <li
          [attr.role]="t.variant === 'danger' ? 'alert' : 'status'"
          [class]="'ds-toast ds-toast--' + t.variant"
        >
          <lucide-icon
            [img]="iconFor(t.variant)"
            [size]="20"
            class="ds-toast__icon"
            aria-hidden="true"
          ></lucide-icon>
          <div class="ds-toast__content">
            @if (t.title) {
              <div class="ds-toast__title">{{ t.title }}</div>
            }
            @if (t.description) {
              <div>{{ t.description }}</div>
            }
          </div>
          <button
            type="button"
            class="ds-toast__close"
            aria-label="Fermer"
            (click)="toastService.dismiss(t.id)"
          >
            <lucide-icon [img]="XIcon" [size]="16" aria-hidden="true"></lucide-icon>
          </button>
        </li>
      }
    </ol>
  `,
    })
], PfToastViewportComponent);
export { PfToastViewportComponent };
